  ('judicial-f0899a01-moex-00266', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何者是搶奪罪的要件？', '["不法所有意圖", "使人受傷", "至使人無法抗拒", "施強暴脅迫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00267', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲於計程車休息站附近欲趁機行竊，見計程車駕駛乙上廁所的空檔，鑽進乙車準備拿走鈔票時，正好乙走 出廁所發現甲正在偷錢。甲拿走紙鈔，欲逃離現場時，被乙發現，甲拾起路邊的木棍毆打乙，乙被毆後倒 臥在地，甲即趕緊離開現場。依實務見解，下列敘述何者正確？', '["甲應成立第328條強盜罪", "甲應成立第325條搶奪罪", "甲應成立第329條準強盜罪", "甲應成立第335條侵占罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00268', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲為家電雜貨公司倉庫庫藏管理人員，因急需用錢，夥同友人乙一同將甫進貨的電器，由乙用貨車載走， 一同在網路上折價轉賣，換取現金週轉。依實務見解，乙應如何論罪？', '["成立刑法第339條詐欺罪之共同正犯", "成立刑法第320條竊盜罪之共同正犯", "成立刑法第336條業務侵占罪之共同正犯", "成立刑法第335條普通侵占罪之共同正犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00269', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲前往臺北謀職不順，走投無路，乃向同鄉乙訴苦。乙表示，可以貸予100萬元救急，限期一個月歸還， 且毋庸利息，只是需要預扣20萬元手續費與逾期不還的違約金20萬元。甲急需用錢，乃向乙借款。關於 乙之行為，下列何者正確？', '["民事借貸，乙不成立犯罪", "乙成立詐欺罪", "乙成立背信罪", "乙成立重利罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00270', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲竊得金飾，以金飾與知情之乙互易手機，甲再將該手機贈與知情之丙。下列敘述何者正確？', '["甲成立竊盜罪及贓物罪；乙成立贓物罪；丙不成立贓物罪", "甲成立竊盜罪；乙成立贓物罪；丙不成立贓物罪", "甲成立竊盜罪及贓物罪；乙丙成立贓物罪", "甲成立竊盜罪；乙丙成立贓物罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00271', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-0f9358e7', 'sub-judicial-f0899a01-03', NULL, 'essay', '過去我國法院之間的審判權爭議係由大法官會議做成統一解釋的方式
來處理，在憲法訴訟法制定後，大法官（憲法法庭）已經不再處理審判
權爭議問題。因而法院組織法制定新規定來處理法院間的審判權爭議問
題。請依據新修正的法院組織法規定，說明我國目前法院之間審判權之
爭議應如何處理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "8a0dfc8d76e1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "法院組織法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00272', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-0f9358e7', 'sub-judicial-f0899a01-03', NULL, 'essay', '我國最高檢察署設置檢察總長，地方檢察署也設置檢察長。請依據法院
組織法與其他相關法律規定，說明最高檢察署檢察總長與地方檢察署檢
察長職權的相同與不同之處為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "8a0dfc8d76e1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "法院組織法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00273', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-0f9358e7', 'sub-judicial-f0899a01-03', NULL, 'essay', '我國行政訴訟在民國 111 年修法前，部分案件由地方法院行政訴訟庭管
轄，修法之後，預計在民國112年8月15日起，過去地方行政訴訟庭管
轄之案件，將改由其他法院進行管轄。請依據新修正之法律，說明112年
8月15日開始，我國行政訴訟的法院事務管轄產生什麼改變？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "8a0dfc8d76e1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "法院組織法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00274', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-0f9358e7', 'sub-judicial-f0899a01-03', NULL, 'essay', '有某知名影星因投資之事業與另一知名影星發生民事糾紛，經媒體大幅
報導，有多位民眾對此事產生興趣，紛紛向負責審理該案之法院表示想
旁聽該案件之審理過程。請問該法院是否可主張，因有過多民眾想到庭
旁聽，將會擾亂法庭秩序，從而禁止民眾旁聽法庭的言詞辯論程序？法
院可以針對該庭審理程序，採取何種管理措施？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "8a0dfc8d76e1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "法院組織法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00275', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非屬行政法之法源？', '["外國立法例", "自治規章", "法定預算", "司法院解釋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
